import math

def find_min_max_stolen(n):
    min_stolen = float('inf')
    max_stolen = -float('inf')

    # Iterate all possible divisors of n (which is (a-1)*(b-2)*(c-2))
    for d1 in get_divisors(n):
        # Iterate all possible divisors of d1 (which is (b-2)*(c-2))
        for d2 in get_divisors(d1):
            if d2 * d2 > d1:
                break
            if d1 % d2 != 0:
                continue
            # a-1 = n / d1
            a = (n // d1) + 1
            # d1 = (b-2)*(c-2)
            # Let d2 be (b-2), then (c-2) = d1 / d2
            b = d2 + 2
            c = (d1 // d2) + 2
            if a >= 1 and b >= 2 and c >= 2:
                original = a * b * c
                stolen = original - n
                if stolen < min_stolen:
                    min_stolen = stolen
                if stolen > max_stolen:
                    max_stolen = stolen
            # Also consider d2 as (c-2) and (b-2) as d1/d2
            # This is symmetric, so no need to swap here as we cover all cases
    return (min_stolen, max_stolen)

def get_divisors(num):
    divisors = set()
    for i in range(1, int(math.isqrt(num)) + 1):
        if num % i == 0:
            divisors.add(i)
            divisors.add(num // i)
    return sorted(divisors)

